import React from 'react';
import styled from 'styled-components';

const Container = styled.div`
  padding: 2rem;
  max-width: 1200px;
  margin: 0 auto;
  background-color: #f9fafb;
`;

const Hero = styled.div`
  text-align: center;
  margin-bottom: 3rem;
`;

const HeroTitle = styled.h1`
  font-size: 2.5rem;
  color: #1a202c;
  font-weight: 700;
`;

const HeroSubtitle = styled.h2`
  font-size: 1.5rem;
  color: #4a5568;
  margin-top: 1rem;
  font-weight: 500;
`;

const Section = styled.section`
  margin-bottom: 3rem;
`;

const SectionTitle = styled.h3`
  font-size: 2rem;
  color: #2d3748;
  margin-bottom: 1.5rem;
  border-bottom: 2px solid #63b3ed;
  display: inline-block;
  padding-bottom: 0.5rem;
`;

const BioText = styled.p`
  font-size: 1rem;
  color: #4a5568;
  line-height: 1.8;
  margin-bottom: 1.5rem;
`;

const SkillsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
`;

const SkillCategory = styled.div``;

const SkillTitle = styled.h4`
  font-size: 1.25rem;
  color: #2d3748;
  margin-bottom: 0.75rem;
  font-weight: 600;
`;

const SkillList = styled.ul`
  list-style: none;
  padding: 0;
`;

const SkillItem = styled.li`
  font-size: 1rem;
  color: #4a5568;
  margin-bottom: 0.5rem;
  padding-left: 1.5rem;
  position: relative;

  &:before {
    content: '✔';
    color: #63b3ed;
    position: absolute;
    left: 0;
    font-size: 1rem;
  }
`;

const About = () => (
  <Container>
    <Hero>
      <HeroTitle>About Me</HeroTitle>
      <HeroSubtitle>
        Business Development Manager & AI Consultant bridging technology and business strategy
      </HeroSubtitle>
    </Hero>

    <Section>
      <SectionTitle>Professional Background</SectionTitle>
      <BioText>
        I am a technology consultant and business development professional with a unique blend of AI/ML technical expertise and strategic market development experience across industries such as automotive, sustainability, and IoT. With an MBA in Technology & Sustainability from Frankfurt School and advanced AI/ML training from leading institutions, I specialize in bridging the gap between complex AI technologies and business value creation.
      </BioText>
      <BioText>
        My hands-on experience includes machine learning, data science, and cloud solutions, complemented by a proven track record in stakeholder management, technical education, and go-to-market strategy for AI-powered products. As a trilingual professional fluent in French, English, and German, I have successfully operated across European, African, and North American markets.
      </BioText>
    </Section>

    <Section>
      <SectionTitle>Technical Skills</SectionTitle>
      <SkillsGrid>
        <SkillCategory>
          <SkillTitle>Business & Strategy</SkillTitle>
          <SkillList>
            <SkillItem>AI Strategy & Roadmap Development</SkillItem>
            <SkillItem>Stakeholder Management</SkillItem>
            <SkillItem>Go-to-Market Strategy</SkillItem>
            <SkillItem>Salesforce CRM</SkillItem>
            <SkillItem>Market Analysis & Positioning</SkillItem>
          </SkillList>
        </SkillCategory>

        <SkillCategory>
          <SkillTitle>AI/ML & Data Science</SkillTitle>
          <SkillList>
            <SkillItem>Machine Learning & Deep Learning</SkillItem>
            <SkillItem>TensorFlow, PyTorch, Scikit-learn</SkillItem>
            <SkillItem>Natural Language Processing</SkillItem>
            <SkillItem>Computer Vision & Time-Series Analysis</SkillItem>
            <SkillItem>MLOps & Model Deployment</SkillItem>
          </SkillList>
        </SkillCategory>

        <SkillCategory>
          <SkillTitle>IoT & Smart Systems</SkillTitle>
          <SkillList>
            <SkillItem>IoT Architecture & Design</SkillItem>
            <SkillItem>Connected Systems Development</SkillItem>
            <SkillItem>Smart Cities & Industrial Automation</SkillItem>
            <SkillItem>Energy Management Solutions</SkillItem>
          </SkillList>
        </SkillCategory>
      </SkillsGrid>
    </Section>
  </Container>
);

export default About;
